INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('1700c05d-6820-452f-8de1-b7fe6e43e857', 'Đặc điểm của Section 3 trong bài thi General Training Reading là gì?', 'multiple_choice', '["Nó dễ hơn Section 1.","Nó chứa nhiều bài quảng cáo nhỏ.","Nó là một văn bản dài, phức tạp, có tính chất miêu tả, tường thuật (narrative) hoặc nghị luận, độ khó tương đương với một bài Academic Reading.","Nó chỉ chứa hình ảnh."]', 'Nó là một văn bản dài, phức tạp, có tính chất miêu tả, tường thuật (narrative) hoặc nghị luận, độ khó tương đương với một bài Academic Reading.', 'Section 3 là ''trùm cuối'' để phân loại điểm số cao (Band 7.0+). Nó thường trích từ tạp chí, sách lịch sử hoặc tiểu sử.'),
('1700c05d-6820-452f-8de1-b7fe6e43e857', 'Dạng câu hỏi nào đánh giá tư duy sâu sắc nhất thường chỉ xuất hiện ở Section 3 của bài thi GT?', 'multiple_choice', '["Fill in the blanks (số lượng).","Multiple Choice Questions hỏi về ''Mục đích chính của tác giả'' (Writer''s purpose) hoặc ''Thái độ của tác giả'' (Writer''s tone).","Matching ngày tháng.","Nối hình ảnh."]', 'Multiple Choice Questions hỏi về ''Mục đích chính của tác giả'' (Writer''s purpose) hoặc ''Thái độ của tác giả'' (Writer''s tone).', 'Bởi vì Section 1 và 2 chỉ là thông tin thực tế vô cảm (factual), chỉ có văn bản dài ở Section 3 mới có các khía cạnh về thái độ và lập luận để khai thác.'),
('1700c05d-6820-452f-8de1-b7fe6e43e857', 'Khi đọc một văn bản tự sự (Narrative) về lịch sử một phát minh trong Section 3, bạn nên đặc biệt chú ý đến các từ vựng chỉ điều gì?', 'multiple_choice', '["Màu sắc.","Thứ tự thời gian (Chronological markers) và Sự thay đổi, chuyển biến (Turning points).","Tên món ăn.","Tính cách của động vật."]', 'Thứ tự thời gian (Chronological markers) và Sự thay đổi, chuyển biến (Turning points).', 'Văn bản tường thuật thường theo dòng thời gian. Việc bắt được các từ như ''Initially'', ''Decades later'', ''However'' giúp bạn dễ dàng theo dõi mạch phát triển của câu chuyện.'),
('d4d25075-106f-45bc-b50b-1b1f5bc7ba0d', 'Chiến thuật quản lý thời gian khôn ngoan nhất cho bài thi General Training Reading là gì?', 'multiple_choice', '["Dành 20 phút cho mỗi phần.","Dành 30 phút cho Section 1, vì nó dễ ăn điểm nhất.","Làm Section 1 & 2 thật nhanh (tối đa 25-30 phút) để dự trữ thời gian tối đa (30-35 phút) cho Section 3 dài và phức tạp nhất.","Bỏ qua Section 3."]', 'Làm Section 1 & 2 thật nhanh (tối đa 25-30 phút) để dự trữ thời gian tối đa (30-35 phút) cho Section 3 dài và phức tạp nhất.', 'Do sự chênh lệch lớn về độ dài và độ phức tạp, việc chia đều 20 phút là sai lầm chết người trong GT Reading.'),
('d4d25075-106f-45bc-b50b-1b1f5bc7ba0d', 'Tại sao việc ''Đọc kỹ từng chữ'' (Reading for detail) ở Section 1 & 2 lại là một sự lãng phí thời gian?', 'multiple_choice', '["Vì bạn sẽ bị phạt điểm nếu đọc chậm.","Vì giám khảo không cho phép.","Vì câu hỏi ở 2 phần này chủ yếu yêu cầu tìm kiếm thông tin cụ thể (Scanning); bạn chỉ cần lướt mắt tìm từ khóa thay vì phải hiểu toàn bộ ngữ cảnh.","Vì tiếng Anh ở đây quá khó hiểu."]', 'Vì câu hỏi ở 2 phần này chủ yếu yêu cầu tìm kiếm thông tin cụ thể (Scanning); bạn chỉ cần lướt mắt tìm từ khóa thay vì phải hiểu toàn bộ ngữ cảnh.', 'Bạn không cần đọc hết 5 nội quy của công ty nếu câu hỏi chỉ hỏi về ''Quy định trang phục'' (Dress code).'),
('d4d25075-106f-45bc-b50b-1b1f5bc7ba0d', 'Cách xử lý nhanh nhất dạng bài ''Matching Information'' trong môi trường văn bản nhiều gạch đầu dòng (Bullet points) là gì?', 'multiple_choice', '["Đọc lần lượt từng gạch đầu dòng.","Đọc câu hỏi trước, xác định keywords đặc trưng, sau đó rà mắt thật nhanh xuống các đề mục phụ (Sub-headings) và các từ in đậm trong bài để khoanh vùng.","Đoán mò.","Viết lại toàn bộ bài."]', 'Đọc câu hỏi trước, xác định keywords đặc trưng, sau đó rà mắt thật nhanh xuống các đề mục phụ (Sub-headings) và các từ in đậm trong bài để khoanh vùng.', 'Trong GT Reading, Layout (bố cục hình thức) là gợi ý quan trọng nhất. Tiêu đề in đậm chính là biển báo chỉ đường đến đáp án.'),
('f3debf7a-26be-4d6f-b480-129f1dc51cf8', 'Sự khác biệt lớn nhất về cấu trúc bài thi giữa IELTS Academic Reading và General Training Reading là gì?', 'multiple_choice', '["Cả hai hoàn toàn giống nhau.","Academic có 3 văn bản dài; GT có thể có tới 5-6 văn bản ngắn chia làm 3 Sections (Sec 1 và Sec 2 chứa nhiều văn bản nhỏ).","Academic dùng tiếng Anh, GT dùng ngôn ngữ khác.","Academic có 60 câu hỏi, GT có 40 câu hỏi."]', 'Academic có 3 văn bản dài; GT có thể có tới 5-6 văn bản ngắn chia làm 3 Sections (Sec 1 và Sec 2 chứa nhiều văn bản nhỏ).', 'Mặc dù cả hai đều kéo dài 60 phút và có 40 câu hỏi, cấu trúc văn bản của GT bị xé lẻ ở phần đầu để phù hợp với ngữ cảnh đọc thông tin thường nhật.'),
('f3debf7a-26be-4d6f-b480-129f1dc51cf8', 'Về mặt đánh giá điểm số (Band Score), sự khác biệt giữa Academic và General Training Reading là gì?', 'multiple_choice', '["Band score được tính bằng nhau cho cùng một số câu đúng.","GT yêu cầu số câu trả lời đúng KHẮT KHE hơn để đạt cùng một Band điểm (Ví dụ: để đạt Band 7.0, Academic cần khoảng 30 câu, trong khi GT cần tới 34 câu).","Academic dễ đạt điểm cao hơn vì ít từ vựng.","GT không có Band 9.0."]', 'GT yêu cầu số câu trả lời đúng KHẮT KHE hơn để đạt cùng một Band điểm (Ví dụ: để đạt Band 7.0, Academic cần khoảng 30 câu, trong khi GT cần tới 34 câu).', 'Bởi vì độ khó của các văn bản trong GT được đánh giá là thấp hơn, thí sinh phải làm đúng nhiều câu hơn để chứng minh được năng lực của mình.'),
('f3debf7a-26be-4d6f-b480-129f1dc51cf8', 'Nguồn tài liệu trích dẫn của IELTS Academic Reading thường lấy từ đâu, trái ngược với General Training?', 'multiple_choice', '["Truyện cổ tích thiếu nhi.","Các tạp chí khoa học, sách giáo khoa đại học, và các ấn phẩm hàn lâm chuyên sâu.","Menu nhà hàng.","Bản tin thời tiết."]', 'Các tạp chí khoa học, sách giáo khoa đại học, và các ấn phẩm hàn lâm chuyên sâu.', 'Academic nhằm đánh giá khả năng theo học Đại học/Sau Đại học, do đó văn bản mang tính chất nghị luận, phân tích lý thuyết (Discursive and Analytical texts).'),
('a80b64ab-5761-40f1-8a94-0e93f1e75217', 'Trong khi làm bài thi GT Reading thực tế, nếu câu trả lời yêu cầu ''TRUE/FALSE/NOT GIVEN'' nhưng bạn ghi vào giấy thi là ''YES/NO/NOT GIVEN'', hậu quả sẽ là gì?', 'multiple_choice', '["Giám khảo sẽ châm chước và vẫn chấm đúng.","Đáp án của bạn sẽ bị tính là SAI hoàn toàn.","Bạn sẽ bị trừ một nửa số điểm.","Giám khảo sẽ yêu cầu bạn làm lại."]', 'Đáp án của bạn sẽ bị tính là SAI hoàn toàn.', 'IELTS yêu cầu sự chính xác tuyệt đối trong việc tuân thủ chỉ dẫn đề bài. Trả lời Yes/No cho câu hỏi True/False là một lỗi sơ đẳng nhưng cực kỳ phổ biến gây mất điểm oan.'),
('a80b64ab-5761-40f1-8a94-0e93f1e75217', 'Khi điền đáp án dạng ''Hoàn thành câu'' (Completion) vào Answer Sheet, việc chép kèm các dấu câu (như dấu phẩy, dấu chấm) từ bài gốc có được chấp nhận không?', 'multiple_choice', '["Bắt buộc phải chép đầy đủ dấu câu.","Tuyệt đối không điền dấu câu, chỉ điền từ vựng, vì các dấu chấm câu có sẵn trong đề bài sẽ làm câu trả lời của bạn bị sai định dạng.","Dấu phẩy được chấp nhận, dấu chấm thì không.","Tùy thuộc vào giám khảo."]', 'Tuyệt đối không điền dấu câu, chỉ điền từ vựng, vì các dấu chấm câu có sẵn trong đề bài sẽ làm câu trả lời của bạn bị sai định dạng.', 'Nếu đáp án là từ ''museum'', bạn chỉ viết chữ ''museum'', tuyệt đối không được viết ''museum.'' (có dấu chấm) vào tờ phiếu trả lời.'),
('a80b64ab-5761-40f1-8a94-0e93f1e75217', 'Lỗi chính tả (Spelling) trong phần thi Reading sẽ bị trừ điểm như thế nào?', 'multiple_choice', '["Sai một chữ cái vẫn được tính điểm nếu giám khảo đọc hiểu.","Sai chính tả (kể cả thiếu ''s'' số nhiều) sẽ bị tính là câu trả lời sai hoàn toàn (0 điểm).","Bị trừ điểm toàn bài thi.","Không bị trừ điểm ở phần GT."]', 'Sai chính tả (kể cả thiếu ''s'' số nhiều) sẽ bị tính là câu trả lời sai hoàn toàn (0 điểm).', 'Reading là phần thi có sẵn từ vựng trên giấy để bạn copy (ngoại trừ dạng T/F/NG). Do đó, sai chính tả do chép sai là không thể tha thứ.'),
('08581156-35b9-438d-8d98-9fc8c27178fa', 'Chủ đề bối cảnh phổ biến nhất trong Section 1 của bài thi IELTS Listening là gì?', 'multiple_choice', '["Một bài giảng sinh học về tế bào.","Một cuộc hội thoại qua điện thoại về các giao dịch hàng ngày (ví dụ: đặt phòng khách sạn, mở tài khoản ngân hàng, đăng ký khóa học).","Một cuộc tranh luận chính trị.","Một bản tin dự báo thời tiết độc thoại."]', 'Một cuộc hội thoại qua điện thoại về các giao dịch hàng ngày (ví dụ: đặt phòng khách sạn, mở tài khoản ngân hàng, đăng ký khóa học).', 'Section 1 luôn là cuộc trò chuyện giao tiếp xã hội cơ bản (Social Survival) giữa 2 người.'),
('08581156-35b9-438d-8d98-9fc8c27178fa', 'Dạng câu hỏi đặc trưng và thường xuyên xuất hiện nhất trong Section 1 Listening là gì?', 'multiple_choice', '["Matching Headings.","Form / Table / Notes Completion (Điền thông tin vào biểu mẫu, bảng biểu).","Viết một bài luận ngắn.","Nối hình ảnh."]', 'Form / Table / Notes Completion (Điền thông tin vào biểu mẫu, bảng biểu).', 'Thí sinh thường phải điền các thông tin cá nhân cụ thể của người gọi điện như: Tên, Số điện thoại, Địa chỉ, Ngày tháng, Giá tiền.'),
('08581156-35b9-438d-8d98-9fc8c27178fa', 'Trong Section 1, bẫy ''Self-correction'' (Tự sửa lỗi) của người nói diễn ra như thế nào?', 'multiple_choice', '["Người nói từ chối trả lời câu hỏi.","Người nói đưa ra một thông tin, sau đó nhận ra mình nhầm lẫn và đính chính lại bằng một thông tin khác ngay sau đó.","Người nói lặp lại câu trả lời 3 lần.","Người nói nhờ người khác trả lời hộ."]', 'Người nói đưa ra một thông tin, sau đó nhận ra mình nhầm lẫn và đính chính lại bằng một thông tin khác ngay sau đó.', 'Ví dụ: ''My number is 091... Oh wait, sorry, it''s 092...''. Thí sinh vội vàng ghi đáp án đầu tiên sẽ rơi vào bẫy kinh điển này.'),
('0fceb390-c01a-4851-b683-928caab5d43b', 'Đặc trưng về cấu trúc nhân vật của Section 2 IELTS Listening là gì?', 'multiple_choice', '["Một cuộc thảo luận giữa 3 người.","Một cuộc hội thoại qua điện thoại.","Một bài độc thoại (Monologue) trong bối cảnh xã hội hàng ngày (ví dụ: hướng dẫn viên du lịch giới thiệu về khu bảo tồn, quản lý chào mừng nhân viên mới).","Một cuộc phỏng vấn xin việc."]', 'Một bài độc thoại (Monologue) trong bối cảnh xã hội hàng ngày (ví dụ: hướng dẫn viên du lịch giới thiệu về khu bảo tồn, quản lý chào mừng nhân viên mới).', 'Section 2 kiểm tra khả năng nghe và theo kịp luồng thông tin liên tục từ một người nói duy nhất trong bối cảnh phi học thuật.'),
('0fceb390-c01a-4851-b683-928caab5d43b', 'Dạng bài cực kỳ phổ biến và là ''nỗi ám ảnh'' của nhiều thí sinh trong Section 2 Listening là gì?', 'multiple_choice', '["Điền số điện thoại.","Map / Plan Labeling (Điền nhãn bản đồ / Sơ đồ vị trí).","Viết lại câu.","Đếm số lượng từ."]', 'Map / Plan Labeling (Điền nhãn bản đồ / Sơ đồ vị trí).', 'Thí sinh phải có khả năng bám sát ngôn ngữ chỉ phương hướng (Spatial language) như ''North of'', ''Adjacent to'', ''Past the bridge'' để không bị lạc đường trên bản đồ.'),
('0fceb390-c01a-4851-b683-928caab5d43b', 'Khi làm bài Map Labeling, điểm bắt đầu (Starting point) của bạn trên bản đồ thường được xác định như thế nào?', 'multiple_choice', '["Tự chọn một điểm bất kỳ.","Luôn bắt đầu từ góc trên bên phải.","Người nói sẽ chỉ rõ vị trí hiện tại (ví dụ: ''You are here at the main entrance'') hoặc có sẵn dấu ''X'' / mũi tên in trên bản đồ.","Bắt đầu từ tòa nhà lớn nhất."]', 'Người nói sẽ chỉ rõ vị trí hiện tại (ví dụ: ''You are here at the main entrance'') hoặc có sẵn dấu ''X'' / mũi tên in trên bản đồ.', 'Xác định đúng vị trí xuất phát là yếu tố sống còn. Mọi phương hướng (trái/phải) đều được tính dựa trên góc nhìn từ điểm xuất phát đó.');